// Benchmark boilerplate generated by Benchmark

import Benchmark
import Differentiation

struct ArrayContainer: Differentiable {
    var a0: [Double]
    var a1: [Double]
    var a2: [Double]
    var a3: [Double]
    var a4: [Double]
    var a5: [Double]
    var a6: [Double]
    var a7: [Double]
    var a8: [Double]
    var a9: [Double]
    
    init(count: Int) {
        let range = 0 ..< count
        self.a0 = range.map({ Double($0) })
        self.a1 = range.map({ Double($0) + 1.0 })
        self.a2 = range.map({ Double($0 % 3) })
        self.a3 = range.map({ Double($0 % 4) })
        self.a4 = range.map({ Double($0) * 2.0 })
        self.a5 = range.map({ Double($0 % 6) })
        self.a6 = range.map({ Double($0 % 7) })
        self.a7 = range.map({ Double($0 % 11) })
        self.a8 = range.map({ Double($0) * 2.1 })
        self.a9 = range.map({ Double($0) * 13.0 })
    }
}

struct CTAContainer: Differentiable {
    var a0: ConstantTimeAccessor<Double>
    var a1: ConstantTimeAccessor<Double>
    var a2: ConstantTimeAccessor<Double>
    var a3: ConstantTimeAccessor<Double>
    var a4: ConstantTimeAccessor<Double>
    var a5: ConstantTimeAccessor<Double>
    var a6: ConstantTimeAccessor<Double>
    var a7: ConstantTimeAccessor<Double>
    var a8: ConstantTimeAccessor<Double>
    var a9: ConstantTimeAccessor<Double>
    
    init(_ array: ArrayContainer) {
        self.a0 = .init(array.a0)
        self.a1 = .init(array.a1)
        self.a2 = .init(array.a2)
        self.a3 = .init(array.a3)
        self.a4 = .init(array.a4)
        self.a5 = .init(array.a5)
        self.a6 = .init(array.a6)
        self.a7 = .init(array.a7)
        self.a8 = .init(array.a8)
        self.a9 = .init(array.a9)
    }
}

@differentiable(reverse, wrt: container)
func runSimulation(container: inout ArrayContainer, totalTime: Double) {
    for dt in stride(from: 0.0, to: totalTime, by: 0.1) {
        takeTimestep(container: &container, deltaTime: dt)
    }
}

@differentiable(reverse, wrt: c)
func takeTimestep(container c: inout ArrayContainer, deltaTime: Double) {
    differentiableZipWith(&c.a0, c.a1, c.a2, c.a3, c.a4, c.a5, c.a6, c.a7, c.a8, c.a9) { v0, v1, v2, v3, v4, v5, v6, v7, v8, v9 in
        v0 * v1 / v2 * v3 / v4 * v5 / v6 * v7 / v8 * v9
    }
}

@differentiable(reverse, wrt: container)
func runSimulation(container: inout CTAContainer, totalTime: Double) {
    for dt in stride(from: 0.0, to: totalTime, by: 0.1) {
        takeTimestep(container: &container, deltaTime: dt)
    }
}

@differentiable(reverse, wrt: c)
func takeTimestep(container c: inout CTAContainer, deltaTime: Double) {
    for i in 0 ..< c.a0.count {
        c.a0.accessElement(at: i)
        c.a1.accessElement(at: i)
        c.a2.accessElement(at: i)
        c.a3.accessElement(at: i)
        c.a4.accessElement(at: i)
        c.a5.accessElement(at: i)
        c.a6.accessElement(at: i)
        c.a7.accessElement(at: i)
        c.a8.accessElement(at: i)
        c.a9.accessElement(at: i)
        let value = c.a0.accessed * c.a1.accessed / c.a2.accessed * c.a3.accessed / c.a4.accessed * c.a5.accessed / c.a6.accessed * c.a7.accessed / c.a8.accessed * c.a9.accessed
        c.a0.update(at: i, with: value)
    }
}

let benchmarks: @Sendable () -> Void = {
    Benchmark.defaultConfiguration.metrics = [
        .peakMemoryResident,
        /// Measure resident memory usage - sampled during runtime (subtracting start of benchmark baseline resident amount)
        .peakMemoryResidentDelta,
        /// Measure virtual memory usage - sampled during runtime
        .peakMemoryVirtual,
        /// Number of small malloc calls
        .mallocCountSmall,
        /// Number of large malloc calls
        .mallocCountLarge,
        /// Number of small+large mallocs
        .mallocCountTotal,
        /// The amount of allocated resident memory according to the memory allocator
        /// by the application (does not include metadata overhead etc)
        .allocatedResidentMemory,
        /// Number of small+large mallocs - small+large frees in resident memory
        .memoryLeaked
    ]
    
    Benchmark.defaultConfiguration.warmupIterations = 0
    
    oldBenchmarks()
    
    Benchmark("container regular execution (array zip)") { benchmark in
        var c = ArrayContainer(count: 1000)
        benchmark.startMeasurement()
        
        runSimulation(container: &c, totalTime: 100.0)
    
        benchmark.stopMeasurement()
        blackHole(c.a0)
    }
    
    Benchmark("container forward execution (array zip)") { benchmark in
        let c = ArrayContainer(count: 1000)
        benchmark.startMeasurement()
        
        let (value, pullback) = valueWithPullback(at: c) { (c: ArrayContainer) -> [Double] in
            var c = c
            runSimulation(container: &c, totalTime: 100.0)
            return c.a0
        }
        benchmark.stopMeasurement()
        let gradient = pullback(Array.DifferentiableView(Array(repeating: 1.0, count: 1000)))
        
        blackHole(value)
        blackHole(gradient)
    }
 
    Benchmark("container reverse execution (array zip)") { benchmark in
        let c = ArrayContainer(count: 1000)
        
        let (value, pullback) = valueWithPullback(at: c) { (c: ArrayContainer) -> [Double] in
            var c = c
            runSimulation(container: &c, totalTime: 100.0)
            return c.a0
        }
        benchmark.startMeasurement()

        let gradient = pullback(Array.DifferentiableView(Array(repeating: 1.0, count: 1000)))
        benchmark.stopMeasurement()

        blackHole(value)
        blackHole(gradient)
    }
    
    Benchmark("container regular execution (cta)") { benchmark in
        var c = CTAContainer(.init(count: 1000))
        
        benchmark.startMeasurement()
        
        runSimulation(container: &c, totalTime: 100.0)

        benchmark.stopMeasurement()
        blackHole(c.a0)
    }
   
    Benchmark("container forward execution (cta)") { benchmark in
        let c = CTAContainer(.init(count: 1000))
        
        benchmark.startMeasurement()
        
        let (value, pullback) = valueWithPullback(at: c) { (c: CTAContainer) -> ConstantTimeAccessor<Double> in
            var c = c
            runSimulation(container: &c, totalTime: 100.0)
            return c.a0
        }
        
        benchmark.stopMeasurement()
        
        let gradient = pullback(ConstantTimeAccessor(Array(repeating: 1.0, count: 1000)))
        
        blackHole(value)
        blackHole(gradient)
    }
    
    Benchmark("container reverse execution (cta)") { benchmark in
        let c = CTAContainer(.init(count: 1000))
        
        
        let (value, pullback) = valueWithPullback(at: c) { (c: CTAContainer) -> ConstantTimeAccessor<Double> in
            var c = c
            runSimulation(container: &c, totalTime: 100.0)
            return c.a0
        }
        benchmark.startMeasurement()

        
        let gradient = pullback(ConstantTimeAccessor(Array(repeating: 1.0, count: 1000)))
        benchmark.stopMeasurement()

        blackHole(value)
        blackHole(gradient)
    }
}
